mapper.select:
SELECT p.id , p.code , p.name , p.spec , p.purchase_unit , p.unit , p.product_group_id , p.product_type_id , p.product_attribute_id , p.is_active , s.name AS supplier_name FROM product p JOIN supplier s ON p.supplier_id = s.id WHERE 1=1
AND p.product_type_id = #{productTypeId}
AND p.product_group_id = #{productGroupId}
AND p.product_attribute_id = #{productAttributeId}
AND p.is_active = #{isActive}
